{{-- Only visible on mobile (lg:hidden) --}}
<nav class="mobile-nav-glass fixed inset-x-0 bottom-0 z-50 lg:hidden" aria-label="{{ __('dashboard.mobile.nav_aria') ?? 'Navegación principal' }}">
    <div class="flex h-16 items-stretch">
        @foreach($items as $item)
            @php
                $isActive = request()->routeIs($item['route']);
            @endphp
            <a wire:navigate
               href="{{ $item['href'] }}"
               class="mobile-nav-item {{ $isActive ? 'mobile-nav-item-active' : '' }} relative flex flex-1 flex-col items-center justify-center gap-[3px] px-1"
               aria-current="{{ $isActive ? 'page' : 'false' }}"
            >
                {{-- Active indicator pill (above the icon, rendered via CSS ::before) --}}

                {{-- Icon --}}
                @if($isActive)
                    <svg class="mobile-nav-icon h-6 w-6 shrink-0" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
                        {!! $item['icon_filled'] !!}
                    </svg>
                @else
                    <svg class="mobile-nav-icon h-5 w-5 shrink-0" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" aria-hidden="true">
                        {!! $item['icon_outline'] !!}
                    </svg>
                @endif

                {{-- Badge --}}
                @if(!empty($item['badge']) && $item['badge'] > 0)
                    <span class="mobile-nav-badge {{ $item['pulse'] ? 'mobile-nav-badge-pulse' : '' }}" aria-label="{{ $item['badge'] }} {{ __('dashboard.mobile.pending') ?? 'pendientes' }}">
                        {{ $item['badge'] > 99 ? '99+' : $item['badge'] }}
                    </span>
                @elseif(!empty($item['badge']) && $item['badge'] === true)
                    {{-- Dot badge (no count) --}}
                    <span class="mobile-nav-badge mobile-nav-badge-pulse" style="min-width:8px;width:8px;height:8px;padding:0;" aria-label="{{ __('dashboard.mobile.pending') ?? 'pendiente' }}"></span>
                @endif

                {{-- Label --}}
                <span class="mobile-nav-label {{ $isActive ? 'font-semibold text-wc-accent' : 'text-wc-text-tertiary' }}">
                    {{ $item['label'] }}
                </span>
            </a>
        @endforeach
    </div>
</nav>
